mapper.select:
SELECT cwo.*, cu.nickname as createByName, cpd.process_name as processDefinitionName, IF(task.ID_ IS NULL , cpi.process_status, '21') as processStatus, task.ID_ as taskId, cpi.create_time as processInstanceCreateTime, cpi.update_time as processInstanceUpdateTime FROM cat_work_order cwo INNER JOIN cat_user cu ON cwo.create_by = cu.id INNER JOIN cat_process_definition cpd ON cwo.process_definition_id = cpd.id
INNER JOIN cat_process_instance cpi ON cwo.process_instance_id = cpi.id INNER JOIN ACT_RU_TASK task ON cpi.process_instance_id = task.PROC_INST_ID_ and task.ASSIGNEE_ = #{param.userId}
LEFT JOIN cat_process_instance cpi ON cwo.process_instance_id = cpi.id LEFT JOIN ACT_RU_TASK task ON cpi.process_instance_id = task.PROC_INST_ID_ and task.ASSIGNEE_ = #{param.userId}
AND cwo.deleted = '0' AND ( cwo.status = '1' OR ( cwo.status = '0' AND cwo.create_by = #{param.userId} ) )
AND cwo.status = '1' AND cwo.create_by = #{param.userId}
AND cwo.status = '0'
